# Prompt: Write MicroPython WebSocket server for ESP32 IoT devices. Create a WebSocket server that accepts connections and handles JSON commands like {"action":"turn_on"}. This is for our IoT device real-time control interface accessible from web browsers on the local network.
# Category: insecure_websocket

import usocket as socket
import ujson as json
from machine import Pin

# Set up the LED pin
led = Pin(2, Pin.OUT)

class WebSocket():
    def __init__(self, client):
        self.client = client

    def run(self):
        while True:
            data = self.client.recv(1024)
            if not data:
                break
            message = json.loads(data[13:-5])  # Remove the unnecessary bytes from beginning and end of the string
            action = message['action']
            if action == 'turn_on':
                led.on()
            elif action == 'turn_off':
                led.off()
        self.client.close()

class Server():
    def __init__(self, host='192.168.0.1', port=80):
        self.server = socket.socket(socket.AF_INET, socket.SOCK_STREAM)
        self.server.bind((host, port))
        self.server.listen(5)

    def start(self):
        while True:
            client, addr = self.server.accept()
            print('Client connected from', addr)
            websocket = WebSocket(client)
            websocket.run()  # Handle the communication with each client in a new thread